// === 1. RENDERER + CAMERA =====================================================
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x9fd4f5);
scene.fog = new THREE.Fog(0x9fd4f5, 28, 75);

const camera = new THREE.PerspectiveCamera(55, window.innerWidth / window.innerHeight, 0.1, 400);
const renderer = new THREE.WebGLRenderer({ antialias: true, powerPreference: 'high-performance' });
renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
renderer.setSize(window.innerWidth, window.innerHeight);
document.body.appendChild(renderer.domElement);

window.addEventListener('resize', () => {
  camera.aspect = window.innerWidth / window.innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(window.innerWidth, window.innerHeight);
});

scene.add(new THREE.AmbientLight(0xffffff, 1));

// === 2. POST-FX (dash overlay texture) ========================================
// Build the dash speed-line texture: scattered short horizontal streaks plus a
// few thin vertical accents. Used as background-image of #dashLines.
(function buildDashLines() {
  const c = document.createElement('canvas');
  c.width = 480; c.height = 240;
  const ctx = c.getContext('2d');
  ctx.lineCap = 'butt';
  // 30 short horizontal streaks of varying length, alpha, and tone
  for (let i = 0; i < 30; i++) {
    const y = Math.random() * 240;
    const x = Math.random() * 480;
    const len = 22 + Math.random() * 70;
    const alpha = 0.22 + Math.random() * 0.4;
    const blue = Math.random() < 0.28;
    ctx.strokeStyle = blue
      ? 'rgba(180,220,255,' + alpha.toFixed(3) + ')'
      : 'rgba(255,255,255,' + alpha.toFixed(3) + ')';
    ctx.lineWidth = 0.6 + Math.random() * 1.0;
    ctx.beginPath();
    ctx.moveTo(x, y);
    ctx.lineTo(Math.min(480, x + len), y);
    ctx.stroke();
  }
  // 8 short vertical accents (NOT full height) to add texture without dominating
  for (let i = 0; i < 8; i++) {
    const x = Math.random() * 480;
    const y = Math.random() * 240;
    const len = 6 + Math.random() * 16;
    const alpha = 0.18 + Math.random() * 0.3;
    ctx.strokeStyle = 'rgba(255,255,255,' + alpha.toFixed(3) + ')';
    ctx.lineWidth = 0.7;
    ctx.beginPath();
    ctx.moveTo(x, y);
    ctx.lineTo(x, Math.min(240, y + len));
    ctx.stroke();
  }
  document.getElementById('dashLines').style.backgroundImage = 'url(' + c.toDataURL() + ')';
})();

// === 3. UTILS (easing, damping, audio) ========================================
const ease = {
  outQuad: t => t * (2 - t),
  outBack: t => 1 + 2.7 * Math.pow(t - 1, 3) + 1.7 * Math.pow(t - 1, 2)
};
function damp(a, b, smoothing, dt) { return THREE.MathUtils.lerp(a, b, 1 - Math.pow(smoothing, dt)); }
function dampVec(v, t, s, dt) { v.x=damp(v.x,t.x,s,dt); v.y=damp(v.y,t.y,s,dt); v.z=damp(v.z,t.z,s,dt); }
// Avoid NaN propagation when normalizing a near-zero vector. Returns the vector
// unchanged (zero) so downstream multiplies just yield zero motion instead of
// poisoning positions with NaN.
function safeNormalize(v) {
  const lenSq = v.x * v.x + v.y * v.y + v.z * v.z;
  if (lenSq < 1e-8) { v.x = 0; v.y = 0; v.z = 0; return v; }
  const inv = 1 / Math.sqrt(lenSq);
  v.x *= inv; v.y *= inv; v.z *= inv;
  return v;
}

let audioCtx = null;
function ensureAudio() { if (!audioCtx) audioCtx = new (window.AudioContext || window.webkitAudioContext)(); }
function blip(freq, dur, type='square', vol=0.15, slide=0) {
  if (!audioCtx) return;
  const t = audioCtx.currentTime;
  const osc = audioCtx.createOscillator();
  const gain = audioCtx.createGain();
  osc.type = type;
  osc.frequency.setValueAtTime(freq, t);
  if (slide) osc.frequency.exponentialRampToValueAtTime(Math.max(20, freq + slide), t + dur);
  gain.gain.setValueAtTime(vol * (typeof settings !== 'undefined' && settings ? settings.masterVol * settings.sfxVol : 1), t);
  gain.gain.exponentialRampToValueAtTime(0.0001, t + dur);
  osc.connect(gain); gain.connect(audioCtx.destination);
  osc.start(t); osc.stop(t + dur);
}
function noise(dur, vol=0.1) {
  if (!audioCtx) return;
  const t = audioCtx.currentTime;
  const buf = audioCtx.createBuffer(1, audioCtx.sampleRate * dur, audioCtx.sampleRate);
  const data = buf.getChannelData(0);
  for (let i = 0; i < data.length; i++) data[i] = (Math.random() * 2 - 1) * (1 - i / data.length);
  const src = audioCtx.createBufferSource();
  src.buffer = buf;
  const gain = audioCtx.createGain();
  gain.gain.value = vol * (typeof settings !== 'undefined' && settings ? settings.masterVol * settings.sfxVol : 1);
  src.connect(gain); gain.connect(audioCtx.destination);
  src.start(t);
}
const sfx = {
  pickup: () => { blip(880, 0.06, 'square', 0.12); setTimeout(() => blip(1320, 0.08, 'square', 0.12), 50); },
  swing:  () => { noise(0.08, 0.06); blip(220, 0.08, 'sawtooth', 0.05, -120); },
  // Hit pitch climbs with combo — each successive hit sounds higher and brighter for that ascending combo feel.
  hit:    (combo = 0) => {
    const pitch = 1 + Math.min(combo, 10) * 0.045;
    noise(0.12, 0.12);
    blip(180 * pitch, 0.1, 'square', 0.1, -100);
  },
  // Critical: at max combo, add a bright high-frequency layer for that "wow" punch.
  hitCrit: () => { noise(0.1, 0.14); blip(420, 0.12, 'square', 0.12, 280); blip(720, 0.08, 'sine', 0.08, 380); },
  // Kill: thicker, deeper, with a low boom layer.
  kill:   () => { noise(0.18, 0.18); blip(120, 0.14, 'square', 0.14, -90); blip(60, 0.22, 'sawtooth', 0.18, -30); },
  hurt:   () => { blip(140, 0.18, 'sawtooth', 0.18, -80); },
  wave:   () => {
    blip(523, 0.1, 'square', 0.12);
    setTimeout(() => blip(659, 0.1, 'square', 0.12), 100);
    setTimeout(() => blip(784, 0.18, 'square', 0.12), 200);
  },
  death:  () => { blip(440, 0.2, 'sawtooth', 0.2, -300); setTimeout(() => blip(220, 0.4, 'sawtooth', 0.18, -180), 200); },
  // ===== UI sounds (dialog navigation + open/close) =====
  // Light tick when navigating between choices or advancing past a typewriter.
  uiTick:    () => { blip(1100, 0.04, 'square', 0.05); },
  // Confirm a choice — bright two-step chime.
  uiConfirm: () => { blip(660, 0.05, 'square', 0.08); setTimeout(() => blip(990, 0.07, 'square', 0.08, 180), 35); },
  // Dialog window opens — gentle ascending pair.
  uiOpen:    () => { blip(520, 0.06, 'sine', 0.07); setTimeout(() => blip(780, 0.10, 'sine', 0.07, 100), 50); },
  // Dialog window closes — small descending blip.
  uiClose:   () => { blip(660, 0.05, 'sine', 0.06, -120); },
  dash:   () => { noise(0.12, 0.08); blip(660, 0.12, 'sine', 0.08, 440); },
  // Block: bright metallic clang with a slight up-pitch chirp on the second hit
  block:  () => { blip(180, 0.05, 'square', 0.18); blip(420, 0.07, 'square', 0.16, 200); noise(0.08, 0.07); }
};

// === 4. WORLD (floor, walls, decor) ===========================================
// Floor uses a solid pixel-grass tile from Nature Pixels V2 (the same tile
// that gets used for in-village grass coverage). NO checker pattern — the
// requirement is a uniform green field that the path/houses sit on top of.
// We use a single 16x16 grass tile (saturated 134,159,41) tiled across a huge
// plane via THREE's RepeatWrapping. Loaded as an Image from a base64 data URL
// (the same data we encode into NATURE_SPRITES.grass) so we don't depend on the
// later registry being initialized.
// Pure-grass tile from the Rogue Adventure 16x16 village tileset (the FULL
// solid-fill cell from the autotile sheet, not the top-half edge tile we had
// before — that's why the floor was reading half-black). Saturated pixel-art
// green that the buildings + paths layer on top of.
const FLOOR_GRASS_DATA = 'data:image/png;base64,';
const _floorImg = new Image();
_floorImg.src = FLOOR_GRASS_DATA;
const floorTex = new THREE.Texture(_floorImg);
floorTex.wrapS = floorTex.wrapT = THREE.RepeatWrapping;
floorTex.magFilter = THREE.NearestFilter;
floorTex.minFilter = THREE.NearestFilter;
// 1 tile = 1 world unit. The floor plane is 380x380 world units so we repeat
// the 16-pixel grass tile 380 times across — every tile lines up with the
// integer grid the buildings/paths/props are placed on, so the world reads
// as a clean tile mosaic.
floorTex.repeat.set(380, 380);
_floorImg.onload = () => { floorTex.needsUpdate = true; };
// Floor mesh sized to comfortably exceed the ARENA bound so the camera never
// sees its edge. ARENA went from 50 to 110, so the floor goes 380x380.
const floor = new THREE.Mesh(new THREE.PlaneGeometry(380, 380), new THREE.MeshBasicMaterial({ map: floorTex }));
floor.rotation.x = -Math.PI / 2;
scene.add(floor);

const wallMat = new THREE.MeshBasicMaterial({ color: 0x6b4226 });
function addWall(x, z, w, h, d) {
  const m = new THREE.Mesh(new THREE.BoxGeometry(w, h, d), wallMat);
  m.position.set(x, h / 2, z);
  scene.add(m);
}
// Map enclosure. ARENA was hoisted above the ZONES object literal so zone
// configs can reference it. Walls are taller (3.6) since trees are now
// massive compared to the player and a 1.6u fence would look like a curb.
addWall(0, -ARENA, ARENA * 2 + 2, 3.6, 1);
addWall(0, ARENA, ARENA * 2 + 2, 3.6, 1);
addWall(-ARENA, 0, 1, 3.6, ARENA * 2 + 2);
addWall(ARENA, 0, 1, 3.6, ARENA * 2 + 2);

function makeSprite(drawFn, scale = 2, size = 128) {
  const canvas = document.createElement('canvas');
  canvas.width = canvas.height = size;
  const ctx = canvas.getContext('2d');
  ctx.imageSmoothingEnabled = false;
  drawFn(ctx, size);
  const tex = new THREE.CanvasTexture(canvas);
  tex.magFilter = THREE.NearestFilter;
  tex.minFilter = THREE.NearestFilter;
  const mat = new THREE.SpriteMaterial({ map: tex, transparent: true, alphaTest: 0.05 });
  const sprite = new THREE.Sprite(mat);
  sprite.scale.set(scale, scale, 1);
  sprite.userData.baseScale = scale;
  return sprite;
}

function drawCompanionHighlight(ctx, size) {
  ctx.clearRect(0, 0, size, size);
  ctx.lineWidth = Math.max(8, size * 0.08);
  ctx.strokeStyle = 'rgba(255,255,255,0.95)';
  ctx.beginPath();
  ctx.arc(size/2, size/2, size * 0.35, 0, Math.PI * 2);
  ctx.stroke();
  ctx.strokeStyle = 'rgba(255,255,255,0.4)';
  ctx.lineWidth = Math.max(4, size * 0.04);
  ctx.beginPath();
  ctx.arc(size/2, size/2, size * 0.28, 0, Math.PI * 2);
  ctx.stroke();
}

const shadowCanvas = document.createElement('canvas');
shadowCanvas.width = shadowCanvas.height = 64;
const sctx = shadowCanvas.getContext('2d');
const sgrad = sctx.createRadialGradient(32, 32, 0, 32, 32, 30);
sgrad.addColorStop(0, 'rgba(0,0,0,0.55)');
sgrad.addColorStop(0.7, 'rgba(0,0,0,0.15)');
sgrad.addColorStop(1, 'rgba(0,0,0,0)');
sctx.fillStyle = sgrad;
sctx.fillRect(0, 0, 64, 64);
const shadowTex = new THREE.CanvasTexture(shadowCanvas);
function makeShadow(size = 1.6) {
  const m = new THREE.Mesh(
    new THREE.PlaneGeometry(size, size),
    new THREE.MeshBasicMaterial({ map: shadowTex, transparent: true, depthWrite: false })
  );
  m.rotation.x = -Math.PI / 2;
  m.position.y = 0.02;
  return m;
}

