// === VILLAGE TILESET (TILESET-VILLAGE-TOP-DOWN) ===============================
// Pixel-art top-down village sprites: houses, church, trees, fences, bridge,
// ground tiles. Used by buildTownDecor() to compose a real village layout.
// All sprites are face-on top-down; pivot is mid-bottom in world placement so
// buildings sit flat on the ground despite billboard rendering.
const VILLAGE_SPRITES = {
  house_1: "data:image/png;base64,",
  house_2: "data:image/png;base64,",
  church: "data:image/png;base64,",
  tree_1: "data:image/png;base64,",
  tree_2: "data:image/png;base64,",
  tree_3: "data:image/png;base64,",
  grass_tile: "data:image/png;base64,",
  ground_tile: "data:image/png;base64,",
  fence_1: "data:image/png;base64,",
  fence_2: "data:image/png;base64,",
  bridge: "data:image/png;base64,",
  pit: "data:image/png;base64,",
  stairs: "data:image/png;base64,",
  grass_detail_1: "data:image/png;base64,",
  grass_detail_2: "data:image/png;base64,",
  grass_detail_3: "data:image/png;base64,",
  ground_detail_1: "data:image/png;base64,",
  ground_detail_2: "data:image/png;base64,",
  water_tile: "data:image/png;base64,",
};

// Pre-load village sprites + texture cache. Mirrors PA_SPRITES setup.
const _villageImages = {};
const _villageTexCache = {};
for (const k of Object.keys(VILLAGE_SPRITES)) {
  const img = new Image();
  img.src = VILLAGE_SPRITES[k];
  _villageImages[k] = img;
}
function getVillageTexture(name) {
  if (_villageTexCache[name]) return _villageTexCache[name];
  const img = _villageImages[name];
  if (!img) { console.warn('VILLAGE_SPRITES missing:', name); return null; }
  const tex = new THREE.Texture(img);
  tex.magFilter = THREE.NearestFilter;
  tex.minFilter = THREE.NearestFilter;
  tex.wrapS = tex.wrapT = THREE.RepeatWrapping;
  if (img.complete && img.naturalWidth) tex.needsUpdate = true;
  else img.addEventListener('load', () => { tex.needsUpdate = true; });
  _villageTexCache[name] = tex;
  return tex;
}

// Make a billboarded sprite from a VILLAGE_SPRITES entry. Aspect-correct:
// the world-y of `scale` matches sprite height; width tracks image aspect.
// Pivot: mid-bottom (y position is the bottom of the sprite, not the center)
// so buildings/trees sit on the ground regardless of height.
function makeVillageSprite(name, height = 4) {
  const tex = getVillageTexture(name);
  // Each instance gets its own clone so its repeat/offset don't leak.
  const matTex = tex.clone();
  matTex.needsUpdate = true;
  matTex.magFilter = THREE.NearestFilter;
  matTex.minFilter = THREE.NearestFilter;
  const mat = new THREE.SpriteMaterial({ map: matTex, transparent: true, depthWrite: false, alphaTest: 0.05 });
  const sprite = new THREE.Sprite(mat);
  sprite.scale.set(height, height, 1);
  sprite.userData.baseScale = height;
  const img = _villageImages[name];
  const fixAspect = () => {
    const w = img.naturalWidth || img.width;
    const h = img.naturalHeight || img.height;
    if (w && h) sprite.scale.set(height * (w / h), height, 1);
  };
  if (img && img.complete && img.naturalWidth) fixAspect();
  else if (img) img.addEventListener('load', fixAspect);
  return sprite;
}



