// === 8a. CHARACTERS + ABILITIES ===============================================
// CHARACTERS: registry of playable characters. Each entry defines visuals, base
// stats, the direction mode, and which abilities slot into Q (slot1) and R (slot2).
// Adding a new character is one entry here plus the sheets in SHEETS.
//
// directionMode: 'lr' = horizontal-only facing (knight-style, single sprite mirrored
// for left). '4way' would use createDirectionalAnimator with up/down/left/right
// sheets and tilt on diagonals (kept as infrastructure for future characters).
const CHARACTERS = {
  knight: {
    name: 'Knight',
    description: 'Sturdy fighter with blade and shield. Bashes enemies away when surrounded.',
    sheets: {
      idle:   'knightIdle',
      walk:   'knightWalk',
      attack: 'knightAttack',
      hurt:   'knightHurt',
      death:  'knightDeath',
    },
    scale: 9, baseY: 0.65, shadowSize: 2.2,
    stats: { maxHealth: 100, moveSpeed: 9, dashCooldown: 0.7 },
    directionMode: 'lr',
    abilities: { slot1: 'shieldBash', slot2: null },
  },
  // Example future character (sheets need to be encoded into SHEETS first):
  // adventurer: {
  //   name: 'Adventurer',
  //   description: 'Quick swordsman with a forward-thrust dash strike.',
  //   sheets: { idle: { down, up, right }, ... },  // 4-way map
  //   scale: 7, baseY: 1.24, shadowSize: 2.0,
  //   stats: { maxHealth: 80, moveSpeed: 11, dashCooldown: 0.5 },
  //   directionMode: '4way',
  //   abilities: { slot1: 'whirlwind', slot2: null },
  // },
};

// ABILITIES: registry of special skills. Each ability has cooldown, an optional
// canActivate gate, and an activate function that runs the effect. The HUD reads
// from this registry to draw cooldown indicators.
const ABILITIES = {
  shieldBash: {
    name: 'Shield Bash',
    description: 'Forward shockwave that knocks all nearby enemies back briefly.',
    cooldown: 5.0,
    iconText: 'SB',
    iconColor: '#ffcc44',
    canActivate: () => state.running && !state.dialog.open && !state.attacking && state.dashTimer <= 0 && state.knockTimer <= 0,
    activate: () => {
      // Visual: shockwave ring + screen flash
      impactRing(state.player.position.clone().setY(0.9), 0xffcc44, 6.5, 0.5);
      state.shake = Math.max(state.shake, 0.05);
      state.cameraZoom = 0.94;
      state.invuln = Math.max(state.invuln, 0.35);
      state.player.material.color.setRGB(1.5, 1.4, 0.9);
      state.blockJustHit = 0.25;  // borrow the yellow flash tint
      sfx.kill();
      // Knock enemies in a 6u radius
      for (const e of state.enemies) {
        const ud = e.userData;
        if (ud.dying) continue;
        const dx = e.position.x - state.player.position.x;
        const dz = e.position.z - state.player.position.z;
        const d = Math.hypot(dx, dz);
        if (d < 6 && d > 0.01) {
          const kn = 8;
          ud.knockVel.set(dx / d * kn, 0, dz / d * kn);
          ud.flash = Math.max(ud.flash, 0.18);
          ud.attackHitDelay = 0;        // cancel any in-progress windup
          ud.attackHitFired = true;     // prevents the cancelled hit from landing
          if (ud.warningFlash) ud.warningFlash = 0;
        }
      }
      burst(state.player.position.clone().setY(0.6), 'yellow', 18, 6, 0.4);
    },
  },
};

// Active character + ability cooldowns. Tracking on state so reset() can clear.
state.activeCharacter = 'knight';
state.abilities = { slot1: null, slot2: null };  // populated by spawnPlayer()

function getCharCfg() { return CHARACTERS[state.activeCharacter]; }

// (Re)build the player sprite, animator, and shadow from the active character's
// config. Removes any prior player from the scene first, so this can be called
// at startup or when switching characters.
function spawnPlayer() {
  const cfg = getCharCfg();
  if (state.player) scene.remove(state.player);
  if (state.playerShadow) scene.remove(state.playerShadow);
  if (state.playerOutline) scene.remove(state.playerOutline);
  const sprite = makeAnimSprite(cfg.scale);
  sprite.userData.baseScale = cfg.scale;
  sprite.userData.baseY = cfg.baseY;
  sprite.userData.facing = 1;
  sprite.userData.cardinalDir = 'right';   // for LR characters; '4way' overrides per frame
  sprite.userData.directionMode = cfg.directionMode;
  sprite.position.set(0, cfg.baseY, 5);
  scene.add(sprite);
  state.player = sprite;
  state.playerAnim = createAnimator(sprite, cfg.sheets, 'idle');
  state.playerShadow = makeShadow(cfg.shadowSize);
  scene.add(state.playerShadow);
  // X-ray silhouette: duplicate sprite that ONLY renders where the depth test
  // fails (i.e. when something is occluding the player). Uses the same animated
  // texture as the player so the silhouette matches the current pose, tinted
  // teal so it's clearly readable through dense forest cover.
  const outlineMat = new THREE.SpriteMaterial({
    map: sprite.material.map,
    color: 0x66e2c8,
    transparent: true,
    opacity: 0.78,
    depthTest: true,
    depthWrite: false,
    depthFunc: THREE.GreaterDepth,
    alphaTest: 0.35,
  });
  const outline = new THREE.Sprite(outlineMat);
  outline.scale.copy(sprite.scale);
  outline.position.copy(sprite.position);
  outline.renderOrder = 200;
  scene.add(outline);
  state.playerOutline = outline;
  // Stats — applied with talent buffs so a continued game keeps its earned
  // stats instead of resetting to base on character spawn.
  state.characterId = state.activeCharacter;
  state.maxHealth = cfg.stats.maxHealth + (state.talents.bonusMaxHP || 0);
  state.moveSpeed = cfg.stats.moveSpeed + (state.talents.moveBonus || 0);
  state.dashCooldownDuration = cfg.stats.dashCooldown;
  state.health = state.maxHealth;
  state.displayHealth = state.maxHealth;
  // Abilities — bind config to slot, reset cooldowns
  state.abilities.slot1 = cfg.abilities && cfg.abilities.slot1
    ? { id: cfg.abilities.slot1, cd: 0 } : null;
  state.abilities.slot2 = cfg.abilities && cfg.abilities.slot2
    ? { id: cfg.abilities.slot2, cd: 0 } : null;
}

function activateAbility(slotKey) {
  const slot = state.abilities[slotKey];
  if (!slot || slot.cd > 0) return;
  const cfg = ABILITIES[slot.id];
  if (!cfg) return;
  if (cfg.canActivate && !cfg.canActivate()) return;
  cfg.activate();
  // Apply MOMENTUM talent: cooldown reduction multiplier.
  slot.cd = cfg.cooldown * (state.talents.cdrMult || 1);
  updateAbilityHUD();  // refresh icon state
}

// Render the ability bar from current slot bindings + cooldowns. Hidden slots
// are display:none so the bar collapses cleanly when a character has only one ability.
function updateAbilityHUD() {
  for (const key of ['slot1', 'slot2']) {
    const el = document.getElementById('ability' + key.charAt(0).toUpperCase() + key.slice(1));
    if (!el) continue;
    const slot = state.abilities[key];
    if (!slot) {
      el.classList.remove('bound');
      el.classList.remove('ready');
      continue;
    }
    el.classList.add('bound');
    const cfg = ABILITIES[slot.id];
    const icon = el.querySelector('.abilityIcon');
    const name = el.querySelector('.abilityName');
    const cd = el.querySelector('.abilityCooldown');
    if (icon && cfg) {
      icon.textContent = cfg.iconText || '?';
      icon.style.color = cfg.iconColor || '#ffe066';
    }
    if (name && cfg) name.textContent = cfg.name;
    const ready = slot.cd <= 0;
    el.classList.toggle('ready', ready);
    if (cd && cfg) {
      const pct = ready ? 0 : (slot.cd / cfg.cooldown) * 100;
      cd.style.height = pct + '%';
    }
  }
}

// Build the player at startup. Subsequent character changes call this again.
spawnPlayer();

