function spawnEnemy(type) {
  const cfg = ENEMY_CFG[type];
  const sprite = makeAnimSprite(cfg.scale);
  // Spawn on a ring 22-32u from the player so they appear nearby but not on top.
  // Clamped to zone bounds (arenaRadius if defined; otherwise the global ARENA).
  // The Pact Arena uses arenaRadius=70 — without this clamp, enemies spawned
  // outside its pillar ring and the player had to chase them through stones.
  const angle = Math.random() * Math.PI * 2;
  const r = 18 + Math.random() * 10;
  const zoneRadius = (state.zone && state.zone.arenaRadius) ? state.zone.arenaRadius - 4 : (ARENA - 2);
  const limit = Math.min(ARENA - 2, zoneRadius);
  const px = state.player.position.x;
  const pz = state.player.position.z;
  let x = Math.max(-limit, Math.min(limit, px + Math.cos(angle) * r));
  let z = Math.max(-limit, Math.min(limit, pz + Math.sin(angle) * r));
  sprite.position.set(x, cfg.baseY, z);
  sprite.userData.type = type;
  sprite.userData.cfg = cfg;
  sprite.userData.baseY = cfg.baseY;
  sprite.userData.speed = cfg.baseSpeed + state.wave * cfg.speedScale;
  sprite.userData.flash = 0;
  sprite.userData.facing = 1;
  sprite.userData.dying = false;
  // Endless Tide HP scaling: when the wave loop is active, every enemy gets a
  // soft HP buff that scales with wave number so a slime at wave 18 has more
  // bite than the same slime at wave 2. +25% per wave on a log curve so the
  // ramp slows into late game (cap ~3.5x base HP). Champions/bosses are
  // already tough enough that they don't need this — applied to non-boss
  // enemies only (isBoss is set on bosses post-spawn).
  let hp = cfg.hp;
  if (state.endless && state.wave > 1) {
    const w = state.wave;
    const scale = 1 + Math.min(2.5, Math.log(w) * 0.65);  // wave 1=1, 5=2.05, 10=2.50, 20=2.95
    hp = Math.max(1, Math.round(cfg.hp * scale));
  }
  sprite.userData.hp = hp;
  sprite.userData.maxHp = hp;
  // Elite/vow-bound enemies start with a permanent hex brand so they visibly
  // pulse purple from the second they appear — a free readability hint that
  // the wave is harder than the green-rim trash mob next to them.
  if (cfg.hexBrandOnSpawn) sprite.userData.hexBrandTimer = cfg.hexBrandOnSpawn;
  sprite.userData.knockVel = new THREE.Vector3();
  sprite.userData.lastHitByAttackId = -1;
  sprite.userData.attackCooldown = 0.6;
  sprite.userData.arrowQueued = false;
  sprite.userData.arrowFireTimer = 0;
  sprite.userData.hitSquash = 0;
  sprite.userData.warningFlash = 0;
  // Enemy melee attack timing: telegraph and damage fire at attackHitDelay seconds
  // after windup starts. attackHitFired guards against double-firing the same swing.
  sprite.userData.attackHitDelay = 0;
  sprite.userData.attackHitFired = false;
  sprite.userData.anim = createAnimator(sprite, cfg.animSet, 'walk');
  sprite.userData.shadow = makeShadow(cfg.shadowSize);
  sprite.userData.shadow.position.set(sprite.position.x, 0.02, sprite.position.z);
  scene.add(sprite.userData.shadow);
  scene.add(sprite);
  // Red x-ray silhouette: same depth-fail trick as the player outline, but
  // tinted HOT pink-red and additively blended so the silhouette glows
  // brightly through dense forest cover. depthFunc=GreaterDepth means the
  // outline only paints pixels where the enemy is behind something — never
  // when standing in the open. Additive over the alpha-tested sprite makes
  // the red read as a glowing threat indicator instead of muddy maroon.
  const outlineMat = new THREE.SpriteMaterial({
    map: sprite.material.map,
    color: 0xff2244,
    transparent: true,
    opacity: 1.0,
    depthTest: true,
    depthWrite: false,
    depthFunc: THREE.GreaterDepth,
    alphaTest: 0.25,
    blending: THREE.AdditiveBlending,
  });
  const outline = new THREE.Sprite(outlineMat);
  outline.scale.set(sprite.scale.x * 1.04, sprite.scale.y * 1.04, 1);
  outline.position.copy(sprite.position);
  outline.renderOrder = 200;
  scene.add(outline);
  sprite.userData.outline = outline;
  state.enemies.push(sprite);
  burst(sprite.position, 'green', 8, 3, 0.3);
}
// === VOW TRIAL — three escalating waves ======================================
// Spawns a fixed roster per wave (no RNG) so difficulty is reproducible.
// Wave 1: 4 vowSlimes — teaches the player elites are tougher than they look.
// Wave 2: 3 vowSlimes + 2 vowSkeletons — mixed with melee + reach.
// Wave 3: 1 vowReaver + 4 vowSlimes — the miniboss carries the wave.
// Each clear heals 25 HP and spawns a banner. Final clear flips the cleared
// flag so Vance's return-line lights up.
function startVowWave(n) {
  const compositions = {
    1: ['vowSlime', 'vowSlime', 'vowSlime', 'vowSlime'],
    2: ['vowSlime', 'vowSlime', 'vowSlime', 'vowSkeleton', 'vowSkeleton'],
    3: ['vowReaver', 'vowSlime', 'vowSlime', 'vowSlime', 'vowSlime'],
  };
  const list = compositions[n] || [];
  list.forEach((t, i) => setTimeout(() => spawnEnemy(t), i * 220));
  showWaveTag('Vow · Breath ' + n + ' / 3');
  // Grace window so the wave-clear watcher doesn't fire between the
  // press-E moment and the first spawn (state.enemies is empty during that gap).
  if (state.vowTrial) {
    state.vowTrial._spawnGraceUntil = (state.time || 0) + 0.6 + (list.length * 0.22);
  }
}

function _vowTrialTick() {
  if (!state.vowTrial || !state.vowTrial.active) return;
  if (state.vowTrial._spawnGraceUntil && state.time < state.vowTrial._spawnGraceUntil) return;
  const live = state.enemies.reduce((n, e) => n + (e.userData.dying ? 0 : 1), 0);
  if (live > 0) return;
  // Cleared current wave. Heal and either advance or finish.
  state.vowTrial.wave += 1;
  state.health = Math.min(state.maxHealth || 100, state.health + 25);
  state.displayHealth = state.health;
  updateHUD();
  if (state.vowTrial.wave >= state.vowTrial.totalWaves) {
    // Final clear — give immediate gratification gold, mark cleared, the
    // Templar recruit + max-HP buff arrive when the player visits Vance.
    state.vowTrial.active = false;
    state.vowTrial.cleared = true;
    advanceQuest(10);
    awardGold(120);
    awardXP(40);
    if (typeof showStoryBanner === 'function') {
      showStoryBanner('THE VOW IS KEPT',
        "+120 gold. Return to Captain Vance — he has more waiting for you.",
        2800);
    }
    if (sfx.kill) sfx.kill();
    return;
  }
  // Brief breather between waves so the player can reposition + heal-aura tick.
  if (typeof showStoryBanner === 'function') {
    showStoryBanner('BREATH ' + state.vowTrial.wave + ' HELD',
      "+25 HP. The wood inhales. Steady.",
      1600);
  }
  setTimeout(() => {
    if (!state.vowTrial || !state.vowTrial.active) return;
    startVowWave(state.vowTrial.wave + 1);
  }, 2600);
}

// === INN RAID — Mira's Last Stand ============================================
// Special "in-town" combat encounter. Spawns enemies near the inn (player has
// to defend Mira's door). Two waves: the first is light skel + slime mix,
// the second adds a vow-bound elite as the final pressure.
function _innRaidStartWave(n) {
  if (!state.innRaid || !state.innRaid.active) return;
  const compositions = {
    1: ['skeleton', 'skeleton', 'slime', 'slime', 'slime', 'undead'],
    2: ['vowSkeleton', 'undead', 'undead', 'rainbowSlime', 'rainbowSlime', 'demonicSlime'],
  };
  const list = compositions[n] || [];
  list.forEach((t, i) => setTimeout(() => spawnEnemy(t), i * 280));
  showWaveTag('Inn Raid · ' + n + ' / 2');
  state.innRaid._spawnGraceUntil = (state.time || 0) + 0.6 + (list.length * 0.28);
  state.innRaid.wave = n;
}

function _innRaidTick() {
  if (!state.innRaid || !state.innRaid.active) return;
  if (state.innRaid._spawnGraceUntil && state.time < state.innRaid._spawnGraceUntil) return;
  const live = state.enemies.reduce((n, e) => n + (e.userData.dying ? 0 : 1), 0);
  if (live > 0) return;
  if (state.innRaid.wave >= state.innRaid.totalWaves) {
    state.innRaid.active = false;
    state.innRaid.cleared = true;
    state.mode = 'town';   // restore peaceful town mode
    awardGold(80);
    awardXP(25);
    if (typeof showStoryBanner === 'function') {
      showStoryBanner('THE DOOR HELD', "+80 gold. Mira is waiting.", 2400);
    }
    return;
  }
  setTimeout(() => {
    if (!state.innRaid || !state.innRaid.active) return;
    _innRaidStartWave(state.innRaid.wave + 1);
  }, 2400);
}

// === POND EVENT — Hollow Crossing bridge ====================================
function _pondEventTick() {
  if (!state.pondEvent || !state.pondEvent.active) return;
  if (state.pondEvent._spawnGraceUntil && state.time < state.pondEvent._spawnGraceUntil) return;
  const live = state.enemies.reduce((n, e) => n + (e.userData.dying ? 0 : 1), 0);
  if (live > 0) return;
  // Cleared. One-time permanent reward + flip back to peaceful so the
  // crossing returns to a quiet wayside village.
  state.pondEvent.active = false;
  state.pondEvent.cleared = true;
  state.mode = 'town';
  awardGold(120);
  awardXP(35);
  state.talents = state.talents || {};
  state.talents.bonusMaxHP = (state.talents.bonusMaxHP || 0) + 10;
  state.maxHealth = (state.maxHealth || 100) + 10;
  state.health = state.maxHealth;
  state.displayHealth = state.health;
  if (typeof showStoryBanner === 'function') {
    showStoryBanner('THE POND IS QUIET', "+120g · +10 max HP · permanent. The bridge is yours.", 2400);
  }
  if (sfx.kill) sfx.kill();
  updateHUD();
}

// === FINAL VIGIL — IRON CHOIR boss arena =====================================
// The endgame encounter. Spawns at the Pact-Stone (forest deep grove) once
// the Mayor opens the way. Three phases:
//   Phase 1 — Two vowReavers walk in lockstep ("the choir doubles").
//   Phase 2 — Six vowSkeletons and a vowSlime tide (chorus reply).
//   Phase 3 — The Pactbreaker — a single vowReaver with permanent hex tint
//     spawned beside the player AND continuous vowSlime ambient pressure.
function startIronChoir() {
  state.ironChoir = state.ironChoir || { active: false, phase: 0, cleared: false };
  state.ironChoir.active = true;
  state.ironChoir.phase = 1;
  state.ironChoir._spawnGraceUntil = (state.time || 0) + 1.5;
  // Phase 1: two reavers, slight stagger.
  setTimeout(() => spawnEnemy('vowReaver'), 200);
  setTimeout(() => spawnEnemy('vowReaver'), 600);
  showWaveTag('IRON CHOIR · 1 / 3');
  if (sfx.wave) sfx.wave();
  state.shake = Math.max(state.shake, 0.12);
  if (typeof showStoryBanner === 'function') {
    showStoryBanner('THE IRON CHOIR', "The wood opens its mouth. Two voices first.", 2400);
  }
}

function _ironChoirAdvance() {
  const ic = state.ironChoir;
  if (!ic || !ic.active) return;
  if (ic.phase === 1) {
    ic.phase = 2;
    ic._spawnGraceUntil = (state.time || 0) + 1.5;
    const list = ['vowSkeleton','vowSkeleton','vowSkeleton','vowSkeleton','vowSkeleton','vowSkeleton','vowSlime','vowSlime'];
    list.forEach((t, i) => setTimeout(() => spawnEnemy(t), i * 220));
    showWaveTag('IRON CHOIR · 2 / 3');
    state.health = Math.min(state.maxHealth || 100, state.health + 40);
    if (typeof showStoryBanner === 'function') {
      showStoryBanner('CHORUS REPLIES', "Six voices answer. +40 HP.", 1800);
    }
  } else if (ic.phase === 2) {
    ic.phase = 3;
    ic._spawnGraceUntil = (state.time || 0) + 1.5;
    setTimeout(() => spawnEnemy('vowReaver'), 200);
    // Trickle pressure: a slime every ~2.5s so the phase has constant heat.
    ic._trickleTimer = (state.time || 0) + 2.5;
    showWaveTag('IRON CHOIR · 3 / 3 · PACTBREAKER');
    state.health = Math.min(state.maxHealth || 100, state.health + 40);
    if (typeof showStoryBanner === 'function') {
      showStoryBanner('THE PACTBREAKER', "One voice. The last voice. +40 HP.", 2200);
    }
  } else if (ic.phase === 3) {
    ic.active = false;
    ic.cleared = true;
    state.finalVigilCleared = true;
    awardGold(400);
    awardXP(150);
    if (typeof showStoryBanner === 'function') {
      showStoryBanner('THE CHOIR FALLS SILENT',
        "+400 gold. Walk back to Mayor Aldric. The road is yours.",
        3200);
    }
    if (sfx.kill) sfx.kill();
  }
}

function _ironChoirTick() {
  const ic = state.ironChoir;
  if (!ic || !ic.active) return;
  if (ic._spawnGraceUntil && state.time < ic._spawnGraceUntil) return;
  // Phase 3 trickle: keep a vowSlime spawning every 2.5s while the Pactbreaker
  // is up. Stops the moment Pactbreaker (last live enemy) dies.
  if (ic.phase === 3 && ic._trickleTimer && state.time >= ic._trickleTimer) {
    spawnEnemy('vowSlime');
    ic._trickleTimer = state.time + 2.5;
  }
  const live = state.enemies.reduce((n, e) => n + (e.userData.dying ? 0 : 1), 0);
  if (live > 0) return;
  _ironChoirAdvance();
}

// === FORGE TRIAL — three tides of iron =======================================
// Different roster from the Vow Trial: this one stresses crowds rather than
// elites, so the player has to spend their cooldowns smartly. Final wave is
// a Reaver duo so even a tanky party can't faceroll it.
function startForgeWave(n) {
  const compositions = {
    1: ['vowSlime', 'vowSlime', 'vowSlime', 'vowSlime', 'vowSlime', 'vowSlime'],
    2: ['vowSkeleton', 'vowSkeleton', 'vowSkeleton', 'vowSlime', 'vowSlime', 'vowSlime', 'vowSlime'],
    3: ['vowReaver', 'vowReaver', 'vowSkeleton', 'vowSkeleton', 'vowSkeleton'],
  };
  const list = compositions[n] || [];
  list.forEach((t, i) => setTimeout(() => spawnEnemy(t), i * 220));
  showWaveTag('Forge · Tide ' + n + ' / 3');
  if (state.forgeTrial) {
    state.forgeTrial._spawnGraceUntil = (state.time || 0) + 0.6 + (list.length * 0.22);
  }
}

function _forgeTrialTick() {
  if (!state.forgeTrial || !state.forgeTrial.active) return;
  if (state.forgeTrial._spawnGraceUntil && state.time < state.forgeTrial._spawnGraceUntil) return;
  const live = state.enemies.reduce((n, e) => n + (e.userData.dying ? 0 : 1), 0);
  if (live > 0) return;
  state.forgeTrial.wave += 1;
  state.health = Math.min(state.maxHealth || 100, state.health + 30);
  state.displayHealth = state.health;
  updateHUD();
  if (state.forgeTrial.wave >= state.forgeTrial.totalWaves) {
    state.forgeTrial.active = false;
    state.forgeTrial.cleared = true;
    awardGold(180);
    awardXP(60);
    if (typeof showStoryBanner === 'function') {
      showStoryBanner('THE IRON HOLDS', "+180 gold. Bren is waiting.", 2800);
    }
    if (sfx.kill) sfx.kill();
    return;
  }
  if (typeof showStoryBanner === 'function') {
    showStoryBanner('TIDE ' + state.forgeTrial.wave + ' HELD', "+30 HP. Hammer the next.", 1600);
  }
  setTimeout(() => {
    if (!state.forgeTrial || !state.forgeTrial.active) return;
    startForgeWave(state.forgeTrial.wave + 1);
  }, 2600);
}

// === MARSH BEACON TRIAL =======================================================
// Three-tide defense at the Marsh Beacon. The third tide spawns the Drowned
// Herald boss. On clear, hand out gold + flip marshBoss.defeated and unlock
// the Salt Reed pickup near the Beacon (state.hasSaltReed).
function startMarshWave(n) {
  const compositions = {
    1: ['skeleton', 'skeleton', 'undead', 'slime', 'slime'],
    2: ['skeleton', 'undead', 'undead', 'rainbowSlime', 'rainbowSlime', 'whiteSlime'],
    3: ['undead', 'undead', 'rainbowSlime'],  // chaff before boss
  };
  const list = compositions[n] || [];
  list.forEach((t, i) => setTimeout(() => spawnEnemy(t), i * 240));
  showWaveTag('Marsh · Tide ' + n + ' / 3');
  if (state.marshBeacon) {
    state.marshBeacon._spawnGraceUntil = (state.time || 0) + 0.7 + (list.length * 0.24);
  }
  // On the third wave, also spawn the boss after a beat.
  if (n === 3) {
    setTimeout(() => { if (state.marshBeacon && state.marshBeacon.active) spawnDrownedHerald(); }, 1600);
  }
}

function _marshBeaconTick() {
  if (!state.marshBeacon || !state.marshBeacon.active) return;
  if (state.marshBeacon._spawnGraceUntil && state.time < state.marshBeacon._spawnGraceUntil) return;
  const live = state.enemies.reduce((n, e) => n + (e.userData.dying ? 0 : 1), 0);
  if (live > 0) return;
  state.marshBeacon.wave += 1;
  state.health = Math.min(state.maxHealth || 100, state.health + 28);
  state.displayHealth = state.health;
  updateHUD();
  if (state.marshBeacon.wave >= state.marshBeacon.totalWaves) {
    state.marshBeacon.active = false;
    state.marshBeacon.cleared = true;
    state.marshBoss = state.marshBoss || { active: false, defeated: false };
    state.marshBoss.defeated = true;
    state.marshQuest = 3;
    state.hasSaltReed = true;  // Salt Reed appears near beacon for Marek
    awardGold(220);
    awardXP(70);
    if (typeof showStoryBanner === 'function') {
      showStoryBanner('THE HERALD FALLS',
        "+220g · Salt Reed taken from the reeds. Bring it to Marek. Yorra waits at the Crossing.",
        3000);
    }
    if (sfx.kill) sfx.kill();
    if (typeof updateObjectiveHUD === 'function') updateObjectiveHUD();
    return;
  }
  if (typeof showStoryBanner === 'function') {
    showStoryBanner('TIDE ' + state.marshBeacon.wave + ' HELD',
      "+28 HP. The Beacon still burns.", 1600);
  }
  setTimeout(() => {
    if (!state.marshBeacon || !state.marshBeacon.active) return;
    startMarshWave(state.marshBeacon.wave + 1);
  }, 2400);
}

// === CATHEDRAL BELL — RING WAVES ==============================================
// Each press of the bell spawns a wave. We track state.cathedralWaveActive so
// the watcher can heal the player between rings. The boss (Hollow Choirmaster)
// spawns on ring 3 directly from interactWardstone.
function startCathedralWave(n) {
  const compositions = {
    1: ['skeleton', 'skeleton', 'skeleton', 'undead', 'undead'],
    2: ['skeleton', 'skeleton', 'undead', 'undead', 'undead', 'rainbowSlime'],
  };
  const list = compositions[n] || [];
  list.forEach((t, i) => setTimeout(() => spawnEnemy(t), i * 240));
  showWaveTag('Cathedral · Ring ' + n);
  state.cathedralWaveActive = true;
  state._cathedralSpawnGraceUntil = (state.time || 0) + 0.7 + (list.length * 0.24);
}

function _cathedralWaveTick() {
  if (state._cathedralSpawnGraceUntil && state.time < state._cathedralSpawnGraceUntil) return;
  const live = state.enemies.reduce((n, e) => n + (e.userData.dying ? 0 : 1), 0);
  if (live > 0) return;
  // Wave between rings cleared. Heal a little, wait for next ring.
  state.cathedralWaveActive = false;
  state.health = Math.min(state.maxHealth || 100, state.health + 22);
  state.displayHealth = state.health;
  updateHUD();
  if (state.cathedralRings < 3) {
    if (typeof showStoryBanner === 'function') {
      showStoryBanner('SILENCE BETWEEN', "+22 HP. Ring the bell again.", 1500);
    }
  }
}

// === BOSS SPAWNS — expansion bosses ==========================================
function spawnDrownedHerald() {
  if (state.zoneId !== 'marsh') return;
  spawnEnemy('drownedHerald');
  const w = state.enemies[state.enemies.length - 1];
  if (w) {
    w.position.set(0, ENEMY_CFG.drownedHerald.baseY, -70);
    if (w.userData.shadow) w.userData.shadow.position.set(0, 0.02, -70);
    if (w.userData.outline) w.userData.outline.position.copy(w.position);
    w.userData.isBoss = true;
    state.shake = Math.max(state.shake, 0.18);
    if (typeof showStoryBanner === 'function') {
      showStoryBanner('THE DROWNED HERALD',
        "Reeds for hair. Salt for a tongue. Hold the Beacon — finish him.",
        2800);
    }
    if (sfx.wave) sfx.wave();
  }
}

function spawnCathedralBoss() {
  if (state.zoneId !== 'cathedral') return;
  spawnEnemy('hollowChoirmaster');
  const w = state.enemies[state.enemies.length - 1];
  if (w) {
    w.position.set(0, ENEMY_CFG.hollowChoirmaster.baseY, -70);
    if (w.userData.shadow) w.userData.shadow.position.set(0, 0.02, -70);
    if (w.userData.outline) w.userData.outline.position.copy(w.position);
    w.userData.isBoss = true;
    w.userData.isCathedralBoss = true;
    state.shake = Math.max(state.shake, 0.2);
    if (typeof showStoryBanner === 'function') {
      showStoryBanner('THE HOLLOW CHOIRMASTER',
        "He hums the silence between notes. Sing him down.",
        2800);
    }
    if (sfx.wave) sfx.wave();
  }
}

function spawnCatacombsBoss() {
  if (state.zoneId !== 'catacombs') return;
  spawnEnemy('firstWatchman');
  const w = state.enemies[state.enemies.length - 1];
  if (w) {
    w.position.set(0, ENEMY_CFG.firstWatchman.baseY, 0);
    if (w.userData.shadow) w.userData.shadow.position.set(0, 0.02, 0);
    if (w.userData.outline) w.userData.outline.position.copy(w.position);
    w.userData.isBoss = true;
    w.userData.isCatacombsBoss = true;
    state.shake = Math.max(state.shake, 0.2);
    if (typeof showStoryBanner === 'function') {
      showStoryBanner('THE FIRST WATCHMAN',
        "Your armor before it was yours. Take it back.",
        2800);
    }
    if (sfx.wave) sfx.wave();
  }
}

// === ENDLESS TIDE / PACT ARENA WAVE LOOP =====================================
// Triggered by Pact-Keeper Vey after the Arena Warden falls. Once `state.endless`
// is true, the wave-clear watcher in update() bumps state.wave and re-runs this
// function. Each wave:
//   * spawns a curated roster of enemies on a ring around the player
//   * scales count, hp, speed, and reward-on-clear with the wave number
//   * every 5 waves: an "elite" wave with vow-bound enemies + bonus champion
//   * every 10 waves: a "boss" wave headed by a vowReaver champion
// Spawning is staggered (110-180ms between spawns) so a 30-enemy wave doesn't
// spike the frame at wave start. Compositions intentionally stay legible:
// trash → ranged → elites → champion. The player should always be able to read
// what's on screen even at wave 25+.
function startWave() {
  if (!state.endless) return;
  state.waveStartTime = state.time;
  state.waveCleared = false;
  const w = state.wave;
  // === COUNT ===
  // Curve: 5 at wave 1, +2 per wave through wave 8, then +1 per wave, soft cap
  // at 36 so frame budget stays sane on long runs. Boss waves cap lower (28)
  // so the champion has space to fight without 30 trash mobs in the way.
  const isBossWave = (w > 0 && w % 10 === 0);
  const isEliteWave = (w > 0 && w % 5 === 0 && !isBossWave);
  let count;
  if (w <= 8) count = 4 + w * 2;            // wave 1=6, wave 8=20
  else count = Math.min(36, 20 + (w - 8));   // wave 9=21 ... 24=36 (cap)
  if (isBossWave) count = Math.min(28, count);
  // === COMPOSITION ===
  // Weighted [type, weight] pool — pool is rebuilt per wave so weights can
  // depend on w. Trash thins as elites ramp; ranged comes online wave 3+.
  const pool = [];
  // Trash core — every wave has slimes, but base 'slime' fades after wave 6.
  pool.push(['slime',         Math.max(0.5, 5 - w * 0.4)]);
  pool.push(['brownSlime',    2.0 + Math.min(2, w * 0.12)]);
  pool.push(['babyblueSlime', 1.5 + Math.min(2, w * 0.10)]);
  if (w >= 2) pool.push(['whiteSlime',   1.2 + Math.min(2.0, w * 0.10)]);
  if (w >= 2) pool.push(['skeleton',     1.0 + Math.min(3.0, w * 0.18)]);
  if (w >= 3) pool.push(['rainbowSlime', 1.0 + Math.min(2.5, w * 0.12)]);
  if (w >= 3) pool.push(['undead',       0.8 + Math.min(2.5, w * 0.14)]);  // ranged archers
  if (w >= 4) pool.push(['blackSlime',   0.6 + Math.min(2.0, w * 0.10)]);
  if (w >= 5) pool.push(['demonicSlime', 0.3 + Math.min(2.0, w * 0.08)]);
  // Vow-bound elites trickle in starting wave 6 and become a real threat 10+.
  if (w >= 6) pool.push(['vowSlime',    0.3 + Math.max(0, (w - 6)) * 0.10]);
  if (w >= 9) pool.push(['vowSkeleton', 0.3 + Math.max(0, (w - 9)) * 0.08]);
  // Build a total-weight cache.
  const totalW = pool.reduce((s, p) => s + p[1], 0);
  // === SPAWN STAGGER ===
  // Slightly slower stagger on bigger waves so the player has time to read
  // each newcomer instead of being instantly mobbed.
  const stagger = (count > 18) ? 150 : 130;
  for (let i = 0; i < count; i++) {
    let r = Math.random() * totalW;
    let type = pool[0][0];
    for (const [t, ww] of pool) { r -= ww; if (r <= 0) { type = t; break; } }
    setTimeout(() => { if (state.endless) spawnEnemy(type); }, i * stagger);
  }
  // === CHAMPIONS ===
  // Boss wave: 1 vowReaver + 1 vowSkeleton, after the regular roster is in.
  // Elite wave: 1 vowSkeleton mid-roster.
  // Both showcased with a separate wave-tag flavor so the player feels the beat.
  if (isBossWave) {
    setTimeout(() => { if (state.endless) spawnEnemy('vowReaver'); }, count * stagger + 600);
    setTimeout(() => { if (state.endless) spawnEnemy('vowSkeleton'); }, count * stagger + 1100);
    showWaveTag('Wave ' + w + ' · CHAMPION');
  } else if (isEliteWave) {
    setTimeout(() => { if (state.endless) spawnEnemy('vowSkeleton'); }, count * stagger + 400);
    showWaveTag('Wave ' + w + ' · ELITE');
  } else {
    showWaveTag('Wave ' + w);
  }
  if (sfx.wave) sfx.wave();
}
function showWaveTag(text) {
  const tag = document.getElementById('waveTag');
  tag.textContent = text;
  tag.classList.remove('show');
  void tag.offsetWidth;
  tag.classList.add('show');
  // BUG FIX: previous version started a fresh setTimeout each call. Two rapid waves
  // could leave the tag stuck visible if the second timer fired before the first.
  // Track the handle on the element so we always cancel the previous timer.
  if (tag._hideTimer) clearTimeout(tag._hideTimer);
  tag._hideTimer = setTimeout(() => { tag.classList.remove('show'); tag._hideTimer = null; }, 1400);
}

