  // unconditionally tear down whatever was there. After a quest-reward chain
  // (closeDialog → _reopenDialogAt → close → ...) some flag could be left in
  // an inconsistent state, and the old "early return if open=true" path would
  // permanently lock the player out of NPC dialogs. Every entry point now
  // starts from a clean slate. The cost (one re-init per E press) is trivial.
  const _box = document.getElementById('dialogBox');
