// Tracks one-time purchases by item id so they don't re-appear on the next visit.
state.shopBought = {};

// Spawn a companion at a random angle around the player so they don't all stack
// on the same tile when the player buys multiple recruits in a row.
function spawnCompanionNearPlayer(type) {
  const ang = Math.random() * Math.PI * 2;
  const r = 2.5 + Math.random() * 1.5;
  const x = state.player.position.x + Math.cos(ang) * r;
  const z = state.player.position.z + Math.sin(ang) * r;
  return spawnCompanion(type, x, z);
}

// Open the shop overlay: fill in current wave + gold, render the item list.
// BUG FIX: lifetime-scoped controller for every listener attached during a shop
// session. closeShop() aborts it so re-opening doesn't pile listeners on stale
// button DOM (which renderShopItems() rebuilds from scratch each call).
let shopAbort = null;
function openShop(source = 'hexsmith', companionType = null) {
  // BULLETPROOF RESET: tear down any lingering dialog state and any prior
  // shop session before spinning up the new one. Without this, the recruiter
  // roster could refuse to render after a long quest chain because state.dialog
  // was still flagged open from a stale code path.
  const _box = document.getElementById('dialogBox');
  if (_box) _box.classList.remove('show');
  state.dialog = state.dialog || {};
  if (state.dialog._abort) { try { state.dialog._abort.abort(); } catch (e) {} }
  state.dialog.open = false;
  state.dialog.npc = null;
  state.dialog.dialogId = null;
  state.dialog.lineIdx = 0;
  state.dialog.choiceIdx = 0;
  state.dialog._sortedChoices = null;
  state.dialog._abort = null;
  // Clear the reopen lock so the very next E press isn't pointlessly swallowed
  // when the player closes the shop and immediately walks back to the same NPC.
  state.dialogReopenLockUntil = 0;
  shopSource = source;
  shopCompanionType = companionType;
  if (shopAbort) shopAbort.abort();
  shopAbort = new AbortController();
  // Defensive: shop items reference state.shopBought everywhere. If a code
  // path nuked it, restore an empty object so canBuy() doesn't throw on
  // undefined.id lookups inside renderShopItems.
  if (!state.shopBought) state.shopBought = {};
  const _waveEl = document.getElementById('shopWaveNum');
  const _goldEl = document.getElementById('shopGoldNum');
  if (_waveEl) _waveEl.textContent = state.wave;
  if (_goldEl) _goldEl.textContent = state.gold;
  if (source === 'companion' && companionType) {
    const name = COMPANION_CFG[companionType]?.name || companionType;
    document.getElementById('shopTitle').textContent = name.toUpperCase() + ' UPGRADES';
    document.getElementById('shopSubtitle').textContent = 'Upgrade ' + name + ' from the field.';
  } else {
    document.getElementById('shopTitle').textContent = 'RECRUIT & UPGRADE';
    document.getElementById('shopSubtitle').textContent = (state.zone ? state.zone.name + ' · ' : '') + 'Spend gold to outfit your run.';
  }
  renderShopItems();
  document.getElementById('shopOverlay').classList.remove('hidden');
}

function closeShop() {
  document.getElementById('shopOverlay').classList.add('hidden');
  if (shopAbort) { shopAbort.abort(); shopAbort = null; }
  shopSource = 'hexsmith';
  shopCompanionType = null;
  state.dialog.nearbyNpc = null;
  // Same reopen grace closeDialog applies (250ms).
  state.dialogReopenLockUntil = (typeof performance !== 'undefined' ? performance.now() : Date.now()) + 250;
  try { updateInteractPrompt(); } catch (e) { /* ignore */ }
}

// Render the items panel from SHOP_ITEMS, gated by canBuy() + cost + once flag.
// Called on open and after every successful purchase to refresh button states.
function renderShopItems() {
  const list = document.getElementById('shopItems');
  if (!list) return;   // shop DOM not mounted yet
  list.innerHTML = '';
  if (!state.shopBought) state.shopBought = {};
  // Companion shop: source must match companion type (e.g. 'lancer'). Other
  // shops: simple equality on item.source.
  const items = SHOP_ITEMS.filter((item) => {
    if (shopSource === 'companion') return item.source === shopCompanionType;
    return item.source === shopSource;
  });
  if (items.length === 0) {
    const note = document.createElement('div');
    if (shopSource === 'companion') {
      const name = COMPANION_CFG[shopCompanionType]?.name || shopCompanionType || 'Companion';
      note.textContent = 'No ' + name.toLowerCase() + ' upgrades available yet.';
    } else {
      note.textContent = 'Nothing for sale here right now.';
    }
    note.style.padding = '20px';
    note.style.opacity = '0.8';
    list.appendChild(note);
    return;
  }
  for (const item of items) {
    const bought = state.shopBought[item.id];
    if (item.once && bought) {
      // One-time items vanish after purchase rather than showing as disabled clutter.
      continue;
    }
    // Defensive: if a custom canBuy throws (e.g. references state that was
    // momentarily undefined during a load), skip the item rather than crashing
    // the whole render — the next render attempt will pick it back up.
    let reqOk = true;
    try { reqOk = !item.canBuy || !!item.canBuy(); }
    catch (e) { console.error('shop canBuy() threw for', item.id, e); continue; }
    // Recruits gated on a quest flag should silently disappear before unlock
    // rather than show as a permanently-disabled row that confuses the player.
    // canBuy returning false here means "not unlocked yet" — hide.
    if (!reqOk && item.id && item.id.indexOf('recruit_') === 0 && item.cost > 100) {
      continue;
    }
    const row = document.createElement('div');
    row.className = 'shopItem';
    const info = document.createElement('div');
    info.className = 'shopItemInfo';
    const nm = document.createElement('div');
    nm.className = 'shopItemName';
    nm.textContent = item.name;
    const ds = document.createElement('div');
    ds.className = 'shopItemDesc';
    ds.textContent = item.desc;
    info.appendChild(nm);
    info.appendChild(ds);
    const btn = document.createElement('button');
    btn.className = 'shopBuyBtn';
    btn.textContent = item.cost + 'g';
    const canAfford = state.gold >= item.cost;
    btn.disabled = !reqOk || !canAfford;
    // Always attach the click handler — the AbortController scopes it to the
    // current shop session. Don't pass a stale signal.
    const opts = (shopAbort && shopAbort.signal && !shopAbort.signal.aborted) ? { signal: shopAbort.signal } : undefined;
    btn.addEventListener('click', () => buyItem(item), opts);
    row.appendChild(info);
    row.appendChild(btn);
    list.appendChild(row);
  }
}

function buyItem(item) {
  if (!item) return;
  if (state.gold < item.cost) return;
  // canBuy may throw on a corrupted state — same defense as renderShopItems.
  try { if (item.canBuy && !item.canBuy()) return; }
  catch (e) { console.error('shop canBuy() threw on buy for', item.id, e); return; }
  state.gold -= item.cost;
  if (!state.shopBought) state.shopBought = {};
  if (item.once) state.shopBought[item.id] = true;
  // The buy callback can spawn a companion which references its sheet config.
  // If it throws (e.g. a missing sheet), refund the gold and surface a popup
  // instead of letting the shop appear silently dead.
  try { item.buy(); }
  catch (e) {
    console.error('shop buy() threw for', item.id, e);
    state.gold += item.cost;
    if (item.once) delete state.shopBought[item.id];
    if (state.player && typeof popText === 'function') {
      popText('Recruit failed', state.player.position.clone().setY(2.6), '#ff6677', 0.9);
    }
  }
  // Refresh: gold display + item list (some buttons may now disable, others
  // may unlock from a newly-recruited companion).
  const _gold = document.getElementById('shopGoldNum');
  if (_gold) _gold.textContent = state.gold;
  updateHUD();
  renderShopItems();
}

// Player chose to leave the shop and start the next wave.
// Disabled in campaign mode. Used to advance to the next arena wave from the
// shop screen. Kept (no-op) so legacy dialog actions don't crash.
